Pipeline: hive/http-input:latest → hive/code-runner:latest or hive/text-processor:latest (validate + verify X-Sig) → hive/llm-agent:latest if you need NL reasoning, else skip LLM → hive/http-output:latest. Store the secret in Hive secrets, not in the graph.

```json
{
  "pipeline": [
    {"image": "hive/http-input:latest", "role": "ingress"},
    {"image": "hive/code-runner:latest", "role": "verify_and_parse"},
    {"image": "hive/http-output:latest", "role": "egress"}
  ],
  "needs_human_review": false
}
```

```json
{
  "summary": "Minimal chatbot",
  "pipeline": [
    {"step": 1, "image": "hive/http-input:latest", "role": "ingress"},
    {"step": 2, "image": "hive/llm-agent:latest", "role": "respond"},
    {"step": 3, "image": "hive/http-output:latest", "role": "egress"}
  ],
  "agent_config_hints": {
    "llm": { "model": "<your-model>", "temperature": 0.2 }
  },
  "open_questions": ["Which provider credentials?"]
}
```

Use hive/llm-agent:latest as runtime. Example skeleton (trim to your needs):

```json
{
  "llm": { "model": "gpt-4o", "temperature": 0, "maxTokens": 2048 },
  "tools": [
    {
      "name": "tickets_search",
      "type": "mcp",
      "serverUrl": "https://mcp.internal/tools",
      "description": "Search tickets read-only",
      "enabled": true
    }
  ],
  "memory": { "type": "none" },
  "guardrails": {
    "contentFilter": "strict",
    "maxTokensPerRequest": 8000,
    "rateLimitRequestsPerMin": 60
  },
  "budget": { "maxTokensPerDay": 500000, "alertWebhook": "https://hooks.example/alert" }
}
```

Under agent_config.a2a add skills with id, name, description, tags; keep hive/llm-agent:latest as executor.

```json
{
  "a2a": {
    "skills": [
      {
        "id": "search.kb",
        "name": "Knowledge search",
        "description": "Retrieve from internal KB",
        "tags": ["rag"]
      },
      {
        "id": "summarize.doc",
        "name": "Summarize document",
        "description": "Summarize uploaded text",
        "tags": ["summary"]
      }
    ]
  }
}
```

```json
{
  "summary": "Agent FR avec budget",
  "agent_config_hints": {
    "llm": { "model": "<modèle>", "temperature": 0.3 },
    "budget": { "maxTokensPerDay": 100000, "maxCostPerMonth": 50 },
    "guardrails": { "rateLimitRequestsPerMin": 30 }
  },
  "pipeline": [
    {"image": "hive/http-input:latest", "role": "ingress"},
    {"image": "hive/llm-agent:latest", "role": "répondre"},
    {"image": "hive/http-output:latest", "role": "sortie"}
  ],
  "open_questions": ["Fournisseur LLM ?"]
}
```
